import{_ as s,c as a,a as e,o as p}from"./app-D7QRhIYN.js";const t={};function l(c,n){return p(),a("div",null,n[0]||(n[0]=[e(`<h1 id="java基础" tabindex="-1"><a class="header-anchor" href="#java基础"><span>JAVA基础</span></a></h1><h2 id="变量的加载顺序" tabindex="-1"><a class="header-anchor" href="#变量的加载顺序"><span>变量的加载顺序</span></a></h2><p>先看是否静态：静态优先级更高； 若都是静态，则无论是代码块还是成员变量，谁先声明谁先执行。</p><p>优先级</p><ol><li>静态成员变量 / 静态代码块: 他们的优先级相同,谁先声明谁先执行</li><li>普通成员变量 / 构造代码块: 他们的优先级相同,谁先声明谁先执行</li><li>构造代码块优先于构造方法执行,每创建一个对象就调用一次构造代码块和构造方法</li><li>普通方法和静态方法没有任何区别,谁先调用就谁先执行</li></ol><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java"><pre><code class="language-java"><span class="line"><span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">Test</span><span class="token punctuation">{</span></span>
<span class="line">  </span>
<span class="line">  <span class="token class-name">String</span> a<span class="token operator">=</span><span class="token number">1</span><span class="token punctuation">;</span><span class="token comment">//变量</span></span>
<span class="line">  <span class="token keyword">static</span> <span class="token class-name">String</span> b<span class="token operator">=</span><span class="token number">2</span><span class="token punctuation">;</span><span class="token comment">//静态变量</span></span>
<span class="line">  <span class="token keyword">static</span> <span class="token keyword">final</span> <span class="token class-name">String</span> c<span class="token operator">=</span><span class="token number">3</span><span class="token punctuation">;</span><span class="token comment">//静态常量</span></span>
<span class="line">  <span class="token class-name">String</span> d<span class="token punctuation">;</span></span>
<span class="line">  <span class="token class-name">String</span> e<span class="token punctuation">;</span></span>
<span class="line">  <span class="token class-name">String</span> f<span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">  <span class="token comment">//静态代码块</span></span>
<span class="line">  <span class="token keyword">static</span><span class="token punctuation">{</span></span>
<span class="line">    d <span class="token operator">=</span> <span class="token number">4</span><span class="token punctuation">;</span></span>
<span class="line">  <span class="token punctuation">}</span></span>
<span class="line">  <span class="token comment">//构造代码块</span></span>
<span class="line">  <span class="token punctuation">{</span></span>
<span class="line">    e <span class="token operator">=</span> <span class="token number">5</span><span class="token punctuation">;</span></span>
<span class="line">  <span class="token punctuation">}</span></span>
<span class="line">  <span class="token comment">//构造方法</span></span>
<span class="line">  <span class="token keyword">public</span> <span class="token class-name">Test</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">{</span></span>
<span class="line">    f <span class="token operator">=</span> <span class="token number">6</span><span class="token punctuation">;</span></span>
<span class="line">  <span class="token punctuation">}</span></span>
<span class="line">  </span>
<span class="line">  <span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token keyword">void</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token class-name">String</span><span class="token punctuation">[</span><span class="token punctuation">]</span> args<span class="token punctuation">)</span><span class="token punctuation">{</span></span>
<span class="line">      g<span class="token operator">=</span> <span class="token number">7</span><span class="token punctuation">;</span></span>
<span class="line">  <span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="控制台输入、输出" tabindex="-1"><a class="header-anchor" href="#控制台输入、输出"><span>控制台输入、输出</span></a></h2><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java"><pre><code class="language-java"><span class="line"><span class="token comment">//输入</span></span>
<span class="line"><span class="token class-name">Scanner</span> scan <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Scanner</span><span class="token punctuation">(</span><span class="token class-name">System</span><span class="token punctuation">.</span>in<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">while</span><span class="token punctuation">(</span>scan<span class="token punctuation">.</span><span class="token function">hasNext</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">{</span></span>
<span class="line">    <span class="token class-name">String</span> str <span class="token operator">=</span> scan<span class="token punctuation">.</span><span class="token function">next</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">//输出</span></span>
<span class="line"><span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span><span class="token string">&quot;hello world&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">printf</span><span class="token punctuation">(</span><span class="token string">&quot;the number is:%f&quot;</span><span class="token punctuation">,</span><span class="token number">12.3</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="list、set、map" tabindex="-1"><a class="header-anchor" href="#list、set、map"><span>List、Set、Map</span></a></h2><h2 id="hashtable" tabindex="-1"><a class="header-anchor" href="#hashtable"><span>HashTable</span></a></h2><p>实现了多线程安全，在几乎所有的方法上都加上了synchronized锁，而加锁的结果就是HashTable操作的效率十分低下。</p><h2 id="hashset" tabindex="-1"><a class="header-anchor" href="#hashset"><span>HashSet</span></a></h2><p>底层通过HashMap实现。因此也是非线程安全的。</p><h2 id="hashmap" tabindex="-1"><a class="header-anchor" href="#hashmap"><span>HashMap</span></a></h2><p>非线程安全。仅适用于单线程中。 实质是一个“链表的数组”，可以通过哈希值直接求出元素对应的下标，因此查询效率极高。</p><h3 id="hashmap处理哈希冲突的方式" tabindex="-1"><a class="header-anchor" href="#hashmap处理哈希冲突的方式"><span>HashMap处理哈希冲突的方式</span></a></h3><p>链地址法</p><h3 id="怎么样会触发hashmap的扩容" tabindex="-1"><a class="header-anchor" href="#怎么样会触发hashmap的扩容"><span>怎么样会触发HashMap的扩容？</span></a></h3><p>size达到阙值（threshold）。threshold = capacity（数组最大长度） * loadfactor（扩容因子）</p><h3 id="插入、查找时-如何为key定位" tabindex="-1"><a class="header-anchor" href="#插入、查找时-如何为key定位"><span>插入、查找时，如何为Key定位</span></a></h3><ol><li>先取hashcode</li><li>根据hashcode获得数组下标</li><li>根据数组下标获得Entry、遍历Entry链表，若hashcode一致、key.equal为true或key相等</li></ol><h3 id="插入时-是插入在链表的头部还是尾部" tabindex="-1"><a class="header-anchor" href="#插入时-是插入在链表的头部还是尾部"><span>插入时，是插入在链表的头部还是尾部</span></a></h3><p>1.8之前：头部。又名头插法。（个人想法：若插入到尾部，还需要遍历链表到尾部，增加了耗时） 1.8及1.8之后：尾部。</p><h3 id="hashmap是怎么遍历的-遍历时可以插入和删除元素吗" tabindex="-1"><a class="header-anchor" href="#hashmap是怎么遍历的-遍历时可以插入和删除元素吗"><span>HashMap是怎么遍历的，遍历时可以插入和删除元素吗？</span></a></h3><p>实现：HashMap.AbstractMapIterator modCount：HashMap用来记录对数据进行插入、删除的次数； expectedModCount：AbstractMapIterator用来记录对数据进行插入、删除的次数；</p><p>若在遍历时执行插入、删除操作，发现modCount和expectedModCount不一样，会抛出异常。</p><ul><li>调用hashmap.remove()或hashmap.put()时，会修改modCount，但不会修改expectedModCount</li><li>调用Iterator.remove()时，会同时修改modCount和expectedModCount</li></ul><p>因此遍历时，不可以插入，可以删除（但要用iterator.remove()）。</p><h3 id="什么是扰动函数" tabindex="-1"><a class="header-anchor" href="#什么是扰动函数"><span>什么是扰动函数？</span></a></h3><p>HashMap为了减少哈希冲突而设计的函数。 在1.8版本的HashMap中，是这样取哈希值的：</p><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java"><pre><code class="language-java"><span class="line"><span class="token keyword">static</span> <span class="token keyword">final</span> <span class="token keyword">int</span> <span class="token function">hash</span><span class="token punctuation">(</span><span class="token class-name">Object</span> key<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line"><span class="token keyword">int</span> h<span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">return</span> <span class="token punctuation">(</span>key <span class="token operator">==</span> <span class="token keyword">null</span><span class="token punctuation">)</span> <span class="token operator">?</span> <span class="token number">0</span> <span class="token operator">:</span> <span class="token punctuation">(</span>h <span class="token operator">=</span> key<span class="token punctuation">.</span><span class="token function">hashCode</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token operator">^</span> <span class="token punctuation">(</span>h <span class="token operator">&gt;&gt;&gt;</span> <span class="token number">16</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>即HashMap的hash方法，就是扰动函数的实现。 采用了 hashcode 的高 16 位和低 16 位异或的方法，去降低 hash 碰撞。 （参考：https://blog.csdn.net/weixin_42373997/article/details/112085344）</p><h3 id="不同java版本hashmap实现的区别" tabindex="-1"><a class="header-anchor" href="#不同java版本hashmap实现的区别"><span>不同JAVA版本HashMap实现的区别</span></a></h3><table><thead><tr><th></th><th>1.6的HashMap</th><th>1.7的HashMap</th><th>1.8的HashMap</th></tr></thead><tbody><tr><td>如何取hashcode</td><td>key.hashcode()</td><td>sun.misc.Hashing.stringHash32((String) key)</td><td>(key == null) ? 0 : (h = key.hashCode()) ^ (h &gt;&gt;&gt; 16)</td></tr><tr><td>如何扩容</td><td>超过阙值，则创建一个容量为原数组2倍的新数组，然后重新计算哈希值存进去</td><td>与1.6一样</td><td>与1.6一样</td></tr><tr><td>如何取数组下标</td><td>hashcode &amp; this.elementData.length - 1</td><td>与1.6一样</td><td></td></tr><tr><td>如何实现链表</td><td>Map.Entry</td><td>Map.Entry</td><td>HashMap.Node、HashMap.TreeNode（树化后）</td></tr><tr><td>在链表哪里插入新的元素</td><td>链表头插入</td><td>链表头插入</td><td>链表尾插入</td></tr><tr><td>迭代器</td><td>HashMap.AbstractMapIterator</td><td>HashMap.AbstractMapIterator</td><td>Spliterator（并行迭代器）</td></tr></tbody></table><h2 id="linkedhashmap" tabindex="-1"><a class="header-anchor" href="#linkedhashmap"><span>LinkedHashMap</span></a></h2><p>事实上LinkedHashMap是HashMap的直接子类，二者唯一的区别是LinkedHashMap在HashMap的基础上，采用双向链表(doubly-linked list)的形式将所有entry连接起来，这样是为保证元素的迭代顺序跟插入顺序相同。</p><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java"><pre><code class="language-java"><span class="line"><span class="token class-name">Entry</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">K</span><span class="token punctuation">,</span><span class="token class-name">V</span><span class="token punctuation">&gt;</span></span><span class="token punctuation">[</span><span class="token punctuation">]</span> table<span class="token punctuation">;</span> <span class="token comment">//存储HashMap的地方</span></span>
<span class="line"><span class="token class-name">Entry</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">K</span><span class="token punctuation">,</span><span class="token class-name">V</span><span class="token punctuation">&gt;</span></span> header<span class="token punctuation">;</span><span class="token comment">//按插入顺序维护的一个链表头部的指针</span></span>
<span class="line"><span class="token class-name">Entry</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">K</span><span class="token punctuation">,</span><span class="token class-name">V</span><span class="token punctuation">&gt;</span></span> tail<span class="token punctuation">;</span><span class="token comment">//链表尾部的指针</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="concurrenthashmap" tabindex="-1"><a class="header-anchor" href="#concurrenthashmap"><span>ConcurrentHashMap</span></a></h3><p>线程安全的Hashmap。</p><p><strong>JDK1.7版本（Segment桶模式，也称为分段锁机制）</strong> ConcurrentHashMap 是一个 Segment 数组，Segment是一个锁， 通过继承 ReentrantLock 来进行加锁，所以每次需要加锁的操作锁住的是一个 segment，这样只要保证每个 Segment 是线程安全的，也就实现了全局的线程安全。</p><p>Segment 内部是由数组+链表组成的。</p><p>segment 数组不能扩容，扩容的是Segment内部的数组。</p><p>默认有16个Segment。（concurrencyLevel=16）</p><p><strong>简单叙述ConcurrentHashMap 1.7中put操作的原理</strong> concurrentHashMap.put: 先取key的hashcode，根据hashcode求出所属Segment的下标（与15进行与操作）；</p><p>求得所属Segment后，调用Segment的put方法；</p><p>segment.put: 先获取独占锁，再根据key的hashcode获得node的下标；</p><p>若node没有value，直接赋值；若node有value，则比较hashcode是否一致，一致则直接覆盖，不一致则比较下个node</p><p><strong>JDK1.8版本（与HashMap类似的数组+链表+红黑树的方式实现）</strong></p><p>1.8摒弃了分段锁机制，使用与HashMap类似的数组+链表+红黑树的结构。 线程安全则是通过CAS和synchronized来实现。</p><p><strong>简单叙述ConcurrentHashMap 1.8中get操作的原理</strong> get操作全程不加锁，只通过volatile关键字修饰Node节点，保证数据的可见性、有序性。但不保证原子性。</p><p><strong>简单叙述ConcurrentHashMap 1.8中put操作的原理</strong> concurrentHashMap.put: 同样，先取key的hashcode，根据hashcode求出所属Node的下标（tabAt(tab, i = (n - 1) &amp; hash)）；</p><p>若下标处node=null，则直接插入新值即可。插入时会进行一次cas操作，若操作失败则证明有并发操作，重新插入一次（casTabAt(...)）；</p><blockquote><p>CAS操作：即调用sun.misc.Unsafe的compareAndSwapObject()方法，传入了node数组、下标、旧值和新值。 原理是先将旧值与node数组下标对应的值比较，若相等，则直接插入新值，返回true（表示操作成功）； 若不相等，则表示数组已经被修改过，直接返回false（表示插入失败）。</p></blockquote><p>若下标处node不为空，则用synchronized将node锁住，再遍历链表去存储值。</p><h2 id="treemap" tabindex="-1"><a class="header-anchor" href="#treemap"><span>TreeMap</span></a></h2><p>以红黑树作为存储结构。</p><h3 id="treemap是有序的吗" tabindex="-1"><a class="header-anchor" href="#treemap是有序的吗"><span>Treemap是有序的吗？</span></a></h3><p>是的。默认排序规则：按照key的字典顺序来排序（升序）。 也可以自定义排序规则（Comparator接口）</p><h3 id="是线程安全类吗" tabindex="-1"><a class="header-anchor" href="#是线程安全类吗"><span>是线程安全类吗？</span></a></h3><p>不是线程安全的。若想线程安全，可通过如下方法：</p><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java"><pre><code class="language-java"><span class="line"><span class="token class-name">SortedMap</span> m <span class="token operator">=</span> <span class="token class-name">Collections</span><span class="token punctuation">.</span><span class="token function">synchronizedSortedMap</span><span class="token punctuation">(</span><span class="token keyword">new</span> <span class="token class-name">TreeMap</span><span class="token punctuation">(</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="红黑树的原理" tabindex="-1"><a class="header-anchor" href="#红黑树的原理"><span>红黑树的原理？</span></a></h3><p>逻辑上是一棵“2-3-4树”。下图可知，2-3-4树是一棵“多叉树”，一个节点里可包含1~3个值。 包含一个值的叫2-节点（2个子树），对应红黑树的黑节点； 包含两个值的叫3-节点（3个子树），对应红黑树的一个黑根、一个红子； 包含三个值的叫4-节点（4个子树），对应红黑树的一个黑根、两个红子；</p><h3 id="为什么有二叉搜索树-bst-还要有平衡二叉树-avl树-为什么又要有红黑树-为什么又会有b-树-为什么又会有b-树" tabindex="-1"><a class="header-anchor" href="#为什么有二叉搜索树-bst-还要有平衡二叉树-avl树-为什么又要有红黑树-为什么又会有b-树-为什么又会有b-树"><span>为什么有二叉搜索树（BST），还要有平衡二叉树（AVL树）？为什么又要有红黑树？为什么又会有B-树？为什么又会有B+树？</span></a></h3><ul><li>二叉搜索树（BST）： 查找最坏情况为O(N)，即树成链表状的时候</li><li>平衡二叉树（AVL）： 在二叉搜索树的基础上，加上了“自平衡”的逻辑（左右子树树高超过1则对树进行旋转），避免树成为链表的形状； 查找的平衡和最坏情况均为O(logN)；</li><li>红黑树（RBT）： 红黑树也是一棵二叉搜索树，查找的时间复杂度最坏情况是O(2logN)，比平衡二叉树稍差，但因为插入、删除操作更简单，旋转操作更少，所以总体性能优于平衡二叉树</li><li>B-树： B-树是一棵多路搜索树，通过增加阶数（增加子树数量），使树变得更“矮”，查询效率就可以比红黑树更高。</li><li>B+树： B+树也是一棵多路搜索树，只不过B+树的数据只存储在叶子节点，且叶子节点之间增了指针相连，方便遍历和范围搜索。 现在大多数数据库的数据以及索引都默认通过B+树来存储。可参考Mysql的数据及索引存储结构。</li></ul><h2 id="队列、栈" tabindex="-1"><a class="header-anchor" href="#队列、栈"><span>队列、栈</span></a></h2><h3 id="stack类-官方不建议使用" tabindex="-1"><a class="header-anchor" href="#stack类-官方不建议使用"><span>Stack类（官方不建议使用）</span></a></h3><ul><li>peek()</li><li>pop()</li><li>push(E)</li></ul><h3 id="queue接口" tabindex="-1"><a class="header-anchor" href="#queue接口"><span>Queue接口</span></a></h3><p><strong>从尾部进队，从头部出队</strong></p><ul><li>offer(e)</li><li>remove()</li><li>poll()</li><li>element()</li><li>peek()</li></ul><h3 id="duque接口-双向队列。既可当栈用-又可当队列用" tabindex="-1"><a class="header-anchor" href="#duque接口-双向队列。既可当栈用-又可当队列用"><span>Duque接口（双向队列。既可当栈用，又可当队列用）</span></a></h3><p>继承了Queue接口。</p><p><strong>常用实现类</strong><br> 最常用： LinkedList<br> 线程安全： LinkedBlockingQueue 限制队列长度： ArrayBlockingQueue<br> 有优先级的： PriorityBlockingQueue</p><p><em><strong>API</strong></em></p><table><thead><tr><th></th><th>第一个元素（头部）</th><th></th><th>第一个元素（尾部）</th><th></th><th>对应Queue方法</th><th></th></tr></thead><tbody><tr><td></td><td>抛出异常</td><td>特殊值（0或null）</td><td>抛出异常</td><td>特殊值（0或null）</td><td>抛出异常</td><td>特殊值（0或null）</td></tr><tr><td>插入</td><td>addFirst</td><td>offerFirst</td><td>addLast</td><td>offerLast</td><td>add = addLast</td><td>offer</td></tr><tr><td>移除</td><td>removeFirst</td><td>pollFirst</td><td>removeLast</td><td>pollLast</td><td>remove = removeFirst</td><td>poll</td></tr><tr><td>检查</td><td>getFirst</td><td>peekFirst</td><td>getLast</td><td>peekLast</td><td>element = getFirst</td><td>peek</td></tr></tbody></table><ul><li><p>当队列（Queue）用：</p><ul><li>offerLast(e)（入队，也可以用offer(e)、add()、addLast(e)）</li><li>E pollFirst() （出队，也可以用poll()、remove()、removeFirst()）</li><li>E peekFirst()（获取头节点（first），也可以用peek()、getFirst()、element()）</li></ul></li><li><p>当栈（Stack）用：</p><ul><li>addFirst(e)（进栈）</li><li>removeFirst()（出栈）</li><li>peekFirst()（获取栈顶元素）</li></ul></li></ul><p>总结：</p><ol><li>add、remove、get方法（Collection接口的方法）若失败，均会抛出异常；</li><li>offer、poll、peek方法（Queue接口的方法）若失败，则会返回null或false；</li><li>后缀为First、Last的均为Deque接口的方法（因为是双端队列）；</li></ol><p><em><strong>实现：</strong></em><br><em><strong>非线程安全：LinkedList、ArrayDeque</strong></em><br><em><strong>LinkedList</strong></em><br> 解决方法：Collections.synchronizedList()<br> 底层是链表：Node(first)-&gt; Node-&gt; Node-&gt; Node-&gt; Node(last)</p><p><em><strong>ArrayDeque</strong></em><br> 变为线程安全：Collections.synchronizedList()<br> 底层是数组+head指针+tail指针：<br> 如何扩容：<br> 申请一个更大的数组(原数组的两倍)，然后将原数组复制过去</p><p><em><strong>线程安全：ConcurrentLinkedQueue（继承Queue接口）、BlockingQueue接口</strong></em></p><p><em><strong>ConcurrentLinkedQueue类</strong></em><br> 通过CAS操作操作（UNSAFE）实现资源同步（无锁）；<br> 队列中无数据时出队、或者队列满了时入队，都会操作失败，但不会阻塞线程，而是返回null或false；想阻塞的话可使用BlockingQueue的实现。<br> 特点：HOPS(延迟更新的策略)的设计</p><p><em><strong>BlockingQueue接口及其实现</strong></em><br><em><strong>BlockingQueue在入队出队失败后，应对方式比ConcurrentLinkedQueue灵活。</strong></em><br> 与ConcurrentLinkedQueue类一样，队列中无数据时出队、或者队列满了时入队，都会操作失败；<br> 但BlockingQueue为操作失败之后提供了多种应对方法：</p><table><thead><tr><th></th><th>抛异常</th><th>特定值</th><th>阻塞</th><th>超时</th></tr></thead><tbody><tr><td>入队</td><td>add(o)</td><td>offer(o)</td><td>put(o)</td><td>offer(o, timeout, timeunit)</td></tr><tr><td>出队</td><td>remove(o)</td><td>poll(o)</td><td>take(o)</td><td>poll(timeout, timeunit)</td></tr><tr><td>检查</td><td>element(o)</td><td>peek(o)</td><td></td><td></td></tr></tbody></table><p>此外还有双端队列BlockingDeque（继承了BlockingQueue）</p><p><em><strong>BlockingQueue的实现</strong></em></p><table><thead><tr><th>类名</th><th>描述</th><th>初始大小</th><th>是否自动扩容</th><th>最大大小</th></tr></thead><tbody><tr><td>ArrayBlockingQueue</td><td>有界数组阻塞队列</td><td>需在new对象时传入大小</td><td>×</td><td>初始大小</td></tr><tr><td>PriorityBlockingQueue</td><td>有界优先级阻塞队列（元素需要继承Comparable接口）</td><td>11</td><td>√</td><td>2147483639(Integer.MAX_VALUE)</td></tr><tr><td>DelayQueue</td><td>无界延迟队列（元素需要继承Delayed接口）</td><td>11</td><td>√</td><td>Integer.MAX_VALUE - 8</td></tr><tr><td>LinkedBlockingQueue</td><td>有界链阻塞队列</td><td>Integer.MAX_VALUE</td><td>×</td><td>初始大小</td></tr><tr><td>SynchronousQueue</td><td>同步队列（内部同时只能够容纳单个元素）</td><td>0，不存储任何元素</td><td></td><td></td></tr></tbody></table><h1 id="java事务" tabindex="-1"><a class="header-anchor" href="#java事务"><span>JAVA事务</span></a></h1><h2 id="_1-事务的概念" tabindex="-1"><a class="header-anchor" href="#_1-事务的概念"><span>1.事务的概念</span></a></h2><p>事务（Transaction）：一般是指要做的或所做的事情。在计算机术语中是指访问并可能更新数据库中各种数据项的一个程序执行单元(unit)。</p><h2 id="_2-事务四个属性-acid" tabindex="-1"><a class="header-anchor" href="#_2-事务四个属性-acid"><span>2.事务四个属性（ACID）</span></a></h2><ol><li>atomicity 原子性<br> 原子性：操作这些指令时，要么全部执行成功，要么全部不执行。只要其中一个指令执行失败，所有的指令都执行失败，数据进行回滚，回到执行指令前的数据状态。</li><li>consistency 一致性<br> 一致性：事务的执行使数据从一个状态转换为另一个状态，但是对于整个数据的完整性保持稳定。</li><li>isolation 隔离性<br> 隔离性：在该事务执行的过程中，无论发生的任何数据的改变都应该只存在于该事务之中，对外界不存在任何影响。只有在事务确定正确提交之后，才会显示该事务对数据的改变。其他事务才能获取到这些改变后的数据。</li><li>durability 持久性<br> 持久性：当事务正确完成后，它对于数据的改变是永久性的。</li></ol><h2 id="_3-并发事务导致的问题" tabindex="-1"><a class="header-anchor" href="#_3-并发事务导致的问题"><span>3.并发事务导致的问题</span></a></h2><p>在许多事务处理同一个数据时，如果没有采取有效的隔离机制，那么并发处理数据时，会带来一些的问题。</p><ol><li><p>脏读(Dirty Read)<br> 当一个事务读取另一个事务尚未提交的修改时，产生脏读。<br> 同一事务内不是脏读。 一个事务开始读取了某行数据，但是另外一个事务已经更新了此数据但没有能够及时提交。这是相当危险的，因为很可能所有的操作都被回滚，也就是说读取出的数据其实是错误的。</p></li><li><p>不可重复读(Nonrepeatable Read)<br> 一个事务对同一行数据重复读取两次，但是却得到了不同的结果。同一查询在同一事务中多次进行，由于其他提交事务所做的修改或删除，每次返回不同的结果集，此时发生不可重复读。</p></li><li><p>幻读(Phantom Reads)<br> 事务在操作过程中进行两次查询，第二次查询的结果包含了第一次查询中未出现的数据（这里并不要求两次查询的SQL语句相同）。这是因为在两次查询过程中有另外一个事务插入数据造成的。 当对某行执行插入或删除操作，而该行属于某个事务正在读取的行的范围时，会发生幻像读问题。</p></li><li><p>丢失修改(Lost Update)<br> 第一类：当两个事务更新相同的数据源，如果第一个事务被提交，第二个却被撤销，那么连同第一个事务做的更新也被撤销。<br> 第二类：有两个并发事务同时读取同一行数据，然后其中一个对它进行修改提交，而另一个也进行了修改提交。这就会造成第一次写操作失效。</p></li></ol><h2 id="_4-事务隔离级别" tabindex="-1"><a class="header-anchor" href="#_4-事务隔离级别"><span>4.事务隔离级别</span></a></h2><p>为了兼顾并发效率和异常控制，在标准SQL规范中，定义了4个事务隔离级别.</p><ol><li><p>读未提交(Read Uncommitted) 直译就是&quot;读未提交&quot;，意思就是即使一个更新语句没有提交，但是别的事务可以读到这个改变。<br> Read Uncommitted允许脏读。</p></li><li><p>读已提交(Read Committed) 直译就是&quot;读提交&quot;，意思就是语句提交以后，即执行了 Commit 以后别的事务就能读到这个改变，只能读取到已经提交的数据。Oracle等多数数据库默认都是该级别。<br> 【原理】读已提交就是改变了释放锁的时机，让事务完成提交后再去释放锁。这样就解决了脏读问题。<br> Read Commited 不允许脏读，但会出现非重复读。</p></li><li><p>可重复读(Repeatable Read)：<br> 直译就是&quot;可以重复读&quot;，这是说在同一个事务里面先后执行同一个查询语句的时候，得到的结果是一样的。<br> 【原理】MVCC（行级锁的升级版，略）<br> Repeatable Read 不允许脏读，不允许非重复读，但是会出现幻象读。</p></li><li><p>串行读(Serializable)<br> 直译就是&quot;序列化&quot;，意思是说这个事务执行的时候不允许别的事务并发执行。完全串行化的读，每次读都需要获得表级共享锁，读写相互都会阻塞。<br> Serializable 不允许不一致现象的出现。</p></li></ol><p>通过不同的隔离级别，可以防止一些并发事务问题，同时级别越高则相应性能越低，这个设置需要根据实际场景进行设置。</p><p>常见商用数据库的默认隔离级别：</p><ul><li>MYSQL 可重复读（RR）</li><li>ORACLE 读已提交（RC）</li><li>SQL SERVER 读已提交（RC）</li></ul><h3 id="不同隔离级别会遇到的问题" tabindex="-1"><a class="header-anchor" href="#不同隔离级别会遇到的问题"><span>不同隔离级别会遇到的问题</span></a></h3><p>（✔为没有解决，✖为可解决）</p><table><thead><tr><th>隔离级别</th><th>脏读</th><th>不可重复读</th><th>幻读</th></tr></thead><tbody><tr><td>读未提交</td><td>✔</td><td>✔</td><td>✔</td></tr><tr><td>读已提交</td><td>✖</td><td>✔</td><td>✔</td></tr><tr><td>可重复读</td><td>✖</td><td>✖</td><td>✔</td></tr><tr><td>串行读</td><td>✖</td><td>✖</td><td>✖</td></tr></tbody></table><h3 id="oracle、sql-server-既然默认的隔离级别为-读已提交-那么它们是怎么解决幻读和不可重复读的" tabindex="-1"><a class="header-anchor" href="#oracle、sql-server-既然默认的隔离级别为-读已提交-那么它们是怎么解决幻读和不可重复读的"><span>Oracle、Sql Server 既然默认的隔离级别为“读已提交”，那么它们是怎么解决幻读和不可重复读的？</span></a></h3><p>解决不可重复读：MVCC机制；<br> 解决幻读：MVCC机制+Next-key Lock锁；</p><h1 id="java多线程" tabindex="-1"><a class="header-anchor" href="#java多线程"><span>JAVA多线程</span></a></h1><h2 id="java新建线程有哪几种方式" tabindex="-1"><a class="header-anchor" href="#java新建线程有哪几种方式"><span>Java新建线程有哪几种方式？</span></a></h2><ul><li>Thread</li></ul><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java"><pre><code class="language-java"><span class="line"><span class="token class-name">Thread</span> t <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Thread</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">t<span class="token punctuation">.</span><span class="token function">run</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>Runnable接口</li></ul><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java"><pre><code class="language-java"><span class="line"> <span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token keyword">void</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token class-name">String</span><span class="token punctuation">[</span><span class="token punctuation">]</span> args<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line"> <span class="token class-name">Thread</span> thread <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Thread</span><span class="token punctuation">(</span><span class="token keyword">new</span> <span class="token class-name">MyRunnable</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"> thread<span class="token punctuation">.</span><span class="token function">start</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"><span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">MyRunnable</span> <span class="token keyword">implements</span> <span class="token operator">&gt;</span><span class="token class-name">Runnable</span> <span class="token punctuation">{</span></span>
<span class="line">   <span class="token annotation punctuation">@Override</span></span>
<span class="line">   <span class="token keyword">public</span> <span class="token keyword">void</span> <span class="token function">run</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">       <span class="token comment">// ...</span></span>
<span class="line">   <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>Callable接口</li></ul><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java"><pre><code class="language-java"><span class="line"><span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token keyword">void</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token class-name">String</span><span class="token punctuation">[</span><span class="token punctuation">]</span> args<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line"> <span class="token class-name">FutureTask</span> task <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">FutureTask</span><span class="token punctuation">(</span><span class="token keyword">new</span> <span class="token class-name">MyCallable</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"> <span class="token class-name">Thread</span> thread <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Thread</span><span class="token punctuation">(</span>task<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"> thread<span class="token punctuation">.</span><span class="token function">join</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">//在thread.start之后，等待线程执行完之后，再继续往下执行</span></span>
<span class="line"> <span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span><span class="token string">&quot;join!&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"> thread<span class="token punctuation">.</span><span class="token function">start</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"> <span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span><span class="token string">&quot;after start!&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"> <span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span><span class="token string">&quot;result=&quot;</span><span class="token operator">+</span>task<span class="token punctuation">.</span><span class="token function">get</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"> <span class="token comment">//最后输出顺序是：join! -&gt; after start! -&gt; generate 123! -&gt; result=123</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"><span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">MyCallable</span> <span class="token keyword">implements</span> </span>
<span class="line"> <span class="token class-name">Callable</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">Integer</span><span class="token punctuation">&gt;</span></span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">public</span> <span class="token class-name">Integer</span> <span class="token function">call</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span><span class="token string">&quot;generate 123!&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token class-name">Thread</span><span class="token punctuation">.</span><span class="token function">currentThread</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">sleep</span><span class="token punctuation">(</span><span class="token number">5000</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token keyword">return</span> <span class="token number">123</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="线程池threadpoolexecutor" tabindex="-1"><a class="header-anchor" href="#线程池threadpoolexecutor"><span>线程池ThreadPoolExecutor</span></a></h2><p>问题：</p><ul><li>创建线程的方式有哪些</li><li>实现runnable和callable的区别</li><li>sleep和wait方法的区别</li><li>为什么不推荐用Executors里提供的线程池初始化的方法？</li></ul><h3 id="线程池的核心参数" tabindex="-1"><a class="header-anchor" href="#线程池的核心参数"><span>线程池的核心参数</span></a></h3><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java"><pre><code class="language-java"><span class="line"><span class="token comment">//线程池实现类&amp;核心参数</span></span>
<span class="line"><span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">ThreadPoolExecutor</span> <span class="token keyword">extends</span> <span class="token class-name">AbstractExecutorService</span><span class="token punctuation">{</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">private</span> <span class="token keyword">final</span> <span class="token class-name">HashSet</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">ThreadPoolExecutor<span class="token punctuation">.</span>Worker</span><span class="token punctuation">&gt;</span></span> workers<span class="token punctuation">;</span><span class="token comment">//线程集合</span></span>
<span class="line"><span class="token keyword">private</span> <span class="token keyword">final</span> <span class="token class-name">BlockingQueue</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">Runnable</span><span class="token punctuation">&gt;</span></span> workQueue<span class="token punctuation">;</span><span class="token comment">//等待被执行的任务队列</span></span>
<span class="line"><span class="token keyword">private</span> <span class="token keyword">final</span> <span class="token class-name">ReentrantLock</span> mainLock<span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">private</span> <span class="token keyword">final</span> <span class="token class-name">Condition</span> termination<span class="token punctuation">;</span></span>
<span class="line"><span class="token comment">//RejectedExecutionHandler默认实现是ThreadPoolExecutor.AbortPolicy</span></span>
<span class="line"><span class="token keyword">private</span> <span class="token keyword">volatile</span> <span class="token class-name">RejectedExecutionHandler</span> handler<span class="token punctuation">;</span><span class="token comment">//入任务队列失败的处理策略</span></span>
<span class="line"><span class="token keyword">private</span> <span class="token keyword">volatile</span> <span class="token class-name">ThreadFactory</span> threadFactory<span class="token punctuation">;</span><span class="token comment">//创建线程的工具</span></span>
<span class="line"></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="线程池的使用" tabindex="-1"><a class="header-anchor" href="#线程池的使用"><span>线程池的使用</span></a></h3><ol><li>生成线程池</li></ol><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java"><pre><code class="language-java"><span class="line"><span class="token doc-comment comment">/**</span>
<span class="line"> 【自定义线程池】</span>
<span class="line"> 参数：</span>
<span class="line"> 1、corePoolSize：核心线程数</span>
<span class="line">        * 核心线程会一直存活，即使没有任务需要执行</span>
<span class="line">        * 当线程数小于核心线程数时，即使有线程空闲，线程池也会优先创建新线程处理</span>
<span class="line">        * 设置allowCoreThreadTimeout=true（默认false）时，核心线程会超时关闭</span>
<span class="line">2、maxPoolSize：最大线程数</span>
<span class="line">        * 当线程数&gt;=corePoolSize、当前没有空闲线程、且任务队列已满时，线程池会创建新线程来处理任务</span>
<span class="line">        * 当线程数=maxPoolSize、当前没有空闲线程、且任务队列已满时，线程池会拒绝处理任务而抛出异常</span>
<span class="line">3、 keepAliveTime：线程空闲时间</span>
<span class="line">        * 当线程空闲时间达到keepAliveTime时，线程会退出，直到线程数量=corePoolSize</span>
<span class="line">        * 如果allowCoreThreadTimeout=true，则会直到线程数量=0</span>
<span class="line">4.  线程空闲时间单位</span>
<span class="line">5.  workQueue 工作队列，用于存储任务在任务被执行之前</span>
<span class="line">6.  threadFactory 线程创建工厂，用于创建线程</span>
<span class="line">7.  RejectedExecutionHandler 当workQueue工作队列达到容量上限时，对任务进行的拒绝策略。</span>
<span class="line">**/</span></span>
<span class="line"><span class="token keyword">public</span> <span class="token class-name">ThreadPoolExecutor</span><span class="token punctuation">(</span><span class="token keyword">int</span> arg0<span class="token punctuation">,</span> <span class="token keyword">int</span> arg1<span class="token punctuation">,</span> <span class="token keyword">long</span> arg2<span class="token punctuation">,</span> <span class="token class-name">TimeUnit</span> arg4<span class="token punctuation">,</span></span>
<span class="line"><span class="token class-name">BlockingQueue</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">Runnable</span><span class="token punctuation">&gt;</span></span> arg5<span class="token punctuation">,</span> <span class="token class-name">ThreadFactory</span> arg6<span class="token punctuation">,</span></span>
<span class="line"><span class="token class-name">RejectedExecutionHandler</span> arg7<span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token doc-comment comment">/**</span>
<span class="line">ExecutorService是接口，ThreadPoolExecutor是该接口的实现</span>
<span class="line">Executors.newCachedThreadPool() 等同于以下写法</span>
<span class="line">**/</span></span>
<span class="line"><span class="token class-name">ExecutorService</span> service <span class="token operator">=</span><span class="token keyword">new</span> <span class="token class-name">ThreadPoolExecutor</span><span class="token punctuation">(</span><span class="token number">0</span><span class="token punctuation">,</span> <span class="token class-name">Integer</span><span class="token punctuation">.</span><span class="token constant">MAX_VALUE</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token number">60L</span><span class="token punctuation">,</span> <span class="token class-name">TimeUnit</span><span class="token punctuation">.</span><span class="token constant">SECONDS</span><span class="token punctuation">,</span>  </span>
<span class="line"><span class="token keyword">new</span> <span class="token class-name">SynchronousQueue</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">Runnable</span><span class="token punctuation">&gt;</span></span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span>  </span>
<span class="line"> </span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ol start="2"><li><p>执行任务<br> 执行任务也有很多API可以用：</p><ul><li>直接使用线程池<br> service.execute() 不支持返回结果</li></ul><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java"><pre><code class="language-java"><span class="line">    <span class="token comment">//新建线程池</span></span>
<span class="line">    <span class="token class-name">ExecutorService</span> service <span class="token operator">=</span><span class="token keyword">new</span> <span class="token class-name">ThreadPoolExecutor</span><span class="token punctuation">(</span><span class="token number">0</span><span class="token punctuation">,</span> <span class="token class-name">Integer</span><span class="token punctuation">.</span><span class="token constant">MAX_VALUE</span><span class="token punctuation">,</span> </span>
<span class="line">     <span class="token number">60L</span><span class="token punctuation">,</span> <span class="token class-name">TimeUnit</span><span class="token punctuation">.</span><span class="token constant">SECONDS</span><span class="token punctuation">,</span> </span>
<span class="line">     <span class="token keyword">new</span> <span class="token class-name">SynchronousQueue</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">Runnable</span><span class="token punctuation">&gt;</span></span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token comment">//无回参</span></span>
<span class="line">    service<span class="token punctuation">.</span><span class="token function">execute</span><span class="token punctuation">(</span><span class="token keyword">new</span> <span class="token class-name">Runnable</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">{</span><span class="token comment">//...});</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>Future接口<br> service.submit() 支持返回结果，结果封装为Future</li></ul><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java"><pre><code class="language-java"><span class="line">    <span class="token comment">//新建线程池</span></span>
<span class="line">    <span class="token class-name">ExecutorService</span> service <span class="token operator">=</span><span class="token keyword">new</span> <span class="token class-name">ThreadPoolExecutor</span><span class="token punctuation">(</span><span class="token number">0</span><span class="token punctuation">,</span> <span class="token class-name">Integer</span><span class="token punctuation">.</span><span class="token constant">MAX_VALUE</span><span class="token punctuation">,</span> </span>
<span class="line">     <span class="token number">60L</span><span class="token punctuation">,</span> <span class="token class-name">TimeUnit</span><span class="token punctuation">.</span><span class="token constant">SECONDS</span><span class="token punctuation">,</span> </span>
<span class="line">     <span class="token keyword">new</span> <span class="token class-name">SynchronousQueue</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">Runnable</span><span class="token punctuation">&gt;</span></span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token comment">//有回参的写法</span></span>
<span class="line">    <span class="token class-name">Future</span> future <span class="token operator">=</span> service<span class="token punctuation">.</span><span class="token function">submit</span><span class="token punctuation">(</span><span class="token keyword">new</span> <span class="token class-name">Callable</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">{</span><span class="token comment">//...});</span></span>
<span class="line"></span>
<span class="line">    <span class="token comment">//获取执行结果（阻塞）</span></span>
<span class="line">    future<span class="token punctuation">.</span><span class="token function">get</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">    <span class="token comment">//获取执行结果（等待一段时间，超时则抛出异常）</span></span>
<span class="line">    <span class="token comment">//future.get(3,TimeUnit.SECONDS);</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li><p>FutureTask类<br> Future的实现类，使用起来跟Future差不多</p><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java"><pre><code class="language-java"><span class="line"></span>
<span class="line">    <span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token keyword">void</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token class-name">String</span><span class="token punctuation">[</span><span class="token punctuation">]</span> args<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">        <span class="token class-name">List</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">FutureTask</span><span class="token punctuation">&gt;</span></span> resultList <span class="token operator">=</span> <span class="token function">test</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">        <span class="token keyword">for</span><span class="token punctuation">(</span><span class="token class-name">FutureTask</span> task<span class="token operator">:</span>resultList<span class="token punctuation">)</span><span class="token punctuation">{</span></span>
<span class="line">            <span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token class-name">String</span><span class="token punctuation">)</span>task<span class="token punctuation">.</span><span class="token function">get</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">        <span class="token punctuation">}</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line">    <span class="token keyword">public</span> <span class="token class-name">List</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">FutureTask</span><span class="token punctuation">&gt;</span></span> <span class="token function">test</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">{</span></span>
<span class="line">        <span class="token class-name">List</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">FutureTask</span><span class="token punctuation">&gt;</span></span> result <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">ArrayList</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token punctuation">&gt;</span></span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">        <span class="token comment">//新建线程池</span></span>
<span class="line">        <span class="token class-name">ExecutorService</span> service <span class="token operator">=</span><span class="token keyword">new</span> <span class="token class-name">ThreadPoolExecutor</span><span class="token punctuation">(</span><span class="token number">0</span><span class="token punctuation">,</span> <span class="token class-name">Integer</span><span class="token punctuation">.</span><span class="token constant">MAX_VALUE</span><span class="token punctuation">,</span> </span>
<span class="line">         <span class="token number">60L</span><span class="token punctuation">,</span> <span class="token class-name">TimeUnit</span><span class="token punctuation">.</span><span class="token constant">SECONDS</span><span class="token punctuation">,</span> </span>
<span class="line">         <span class="token keyword">new</span> <span class="token class-name">SynchronousQueue</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">Runnable</span><span class="token punctuation">&gt;</span></span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">        <span class="token keyword">for</span><span class="token punctuation">(</span><span class="token keyword">int</span> i<span class="token operator">=</span><span class="token number">0</span><span class="token punctuation">;</span>i<span class="token operator">&lt;</span><span class="token number">10</span><span class="token punctuation">;</span>i<span class="token operator">++</span><span class="token punctuation">)</span><span class="token punctuation">{</span></span>
<span class="line">            <span class="token class-name">FutureTask</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">String</span><span class="token punctuation">&gt;</span></span> task <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">FutureTask</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">String</span><span class="token punctuation">&gt;</span></span><span class="token punctuation">(</span><span class="token keyword">new</span> <span class="token class-name">Callable</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">String</span><span class="token punctuation">&gt;</span></span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">                <span class="token annotation punctuation">@Override</span></span>
<span class="line">                <span class="token keyword">public</span> <span class="token class-name">String</span> <span class="token function">call</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token keyword">throws</span> <span class="token class-name">Exception</span> <span class="token punctuation">{</span></span>
<span class="line">                    <span class="token keyword">return</span> <span class="token string">&quot;hello&quot;</span><span class="token punctuation">;</span></span>
<span class="line">                <span class="token punctuation">}</span></span>
<span class="line">            <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">            service<span class="token punctuation">.</span><span class="token function">submit</span><span class="token punctuation">(</span>task<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">            result<span class="token punctuation">.</span><span class="token function">add</span><span class="token punctuation">(</span>task<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">        <span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line">        <span class="token keyword">return</span> result<span class="token punctuation">;</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line">    </span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li><li><p>CompletionService接口（JDK1.8前推荐用这个） 有一个实现类为ExecutorCompletionService<br> 推荐理由：可以使得先完成的任务先被取出，减少了不必要的等待时间</p><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java"><pre><code class="language-java"><span class="line">    <span class="token comment">//创建线程池，并且包一层CompletionService</span></span>
<span class="line">    <span class="token class-name">ExecutorService</span> service <span class="token operator">=</span><span class="token keyword">new</span> <span class="token class-name">ThreadPoolExecutor</span><span class="token punctuation">(</span><span class="token number">0</span><span class="token punctuation">,</span> <span class="token class-name">Integer</span><span class="token punctuation">.</span><span class="token constant">MAX_VALUE</span><span class="token punctuation">,</span><span class="token number">60L</span><span class="token punctuation">,</span> <span class="token class-name">TimeUnit</span><span class="token punctuation">.</span><span class="token constant">SECONDS</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token keyword">new</span> <span class="token class-name">SynchronousQueue</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">Runnable</span><span class="token punctuation">&gt;</span></span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token class-name">CompletionService</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">Integer</span><span class="token punctuation">&gt;</span></span> cService <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">ExecutorCompletionService</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">Integer</span><span class="token punctuation">&gt;</span></span><span class="token punctuation">(</span>service<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">    <span class="token comment">// 向里面扔10个任务</span></span>
<span class="line">    <span class="token keyword">for</span> <span class="token punctuation">(</span><span class="token keyword">int</span> i <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span> i <span class="token operator">&lt;</span> <span class="token number">10</span><span class="token punctuation">;</span> i<span class="token operator">++</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">        <span class="token comment">//这边不是直接通过线程池来提交任务，而是通过CompletionService来提交</span></span>
<span class="line">        cService<span class="token punctuation">.</span><span class="token function">submit</span><span class="token punctuation">(</span><span class="token keyword">new</span> <span class="token class-name">WorkTask</span><span class="token punctuation">(</span><span class="token string">&quot;ExecTask&quot;</span> <span class="token operator">+</span> i<span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>  </span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line">    <span class="token comment">// 检查线程池任务执行结果</span></span>
<span class="line">    <span class="token keyword">for</span> <span class="token punctuation">(</span><span class="token keyword">int</span> i <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span> i <span class="token operator">&lt;</span> <span class="token number">10</span><span class="token punctuation">;</span> i<span class="token operator">++</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">        </span>
<span class="line">        <span class="token comment">//获取执行结果。10个任务中，最先计算出结果的就最先被获得。</span></span>
<span class="line">        <span class="token keyword">int</span> sleptTime <span class="token operator">=</span> cService<span class="token punctuation">.</span><span class="token function">take</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">get</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">        <span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span><span class="token string">&quot; slept &quot;</span><span class="token operator">+</span>sleptTime<span class="token operator">+</span><span class="token string">&quot; ms ...&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li><li><p>CompletableFuture类（JDK1.8后推荐用这个）<br> 自带线程池(ForkJoinPool.commonPool())，无需手工创建。<br> 当然也可以使用手动创建的线程池</p><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java"><pre><code class="language-java"><span class="line"><span class="token class-name">CompletableFuture</span> comFuture <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">CompletableFuture</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token comment">//从线程池获取一个线程并执行任务（无返回值）</span></span>
<span class="line"><span class="token class-name">Runnable</span> runnable <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Runnable</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token annotation punctuation">@Override</span></span>
<span class="line">    <span class="token keyword">public</span> <span class="token keyword">void</span> <span class="token function">run</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">        <span class="token class-name">Integer</span> intResult <span class="token operator">=</span> <span class="token number">1</span><span class="token operator">+</span><span class="token number">1</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token class-name">CompletableFuture</span><span class="token punctuation">.</span><span class="token function">runAsync</span><span class="token punctuation">(</span>runnable<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">//从线程池获取一个线程并执行任务（有返回值）</span></span>
<span class="line"><span class="token keyword">try</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token class-name">Integer</span> result <span class="token operator">=</span> <span class="token class-name">CompletableFuture</span><span class="token punctuation">.</span><span class="token function">supplyAsync</span><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token operator">-&gt;</span><span class="token punctuation">{</span></span>
<span class="line">        <span class="token class-name">Integer</span> intResult <span class="token operator">=</span> <span class="token number">1</span><span class="token operator">+</span><span class="token number">1</span><span class="token punctuation">;</span></span>
<span class="line">        <span class="token keyword">return</span> intResult<span class="token punctuation">;</span></span>
<span class="line">    <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">get</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span> <span class="token keyword">catch</span> <span class="token punctuation">(</span><span class="token class-name">InterruptedException</span> e<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">throw</span> <span class="token keyword">new</span> <span class="token class-name">RuntimeException</span><span class="token punctuation">(</span>e<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span> <span class="token keyword">catch</span> <span class="token punctuation">(</span><span class="token class-name">ExecutionException</span> e<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">throw</span> <span class="token keyword">new</span> <span class="token class-name">RuntimeException</span><span class="token punctuation">(</span>e<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">//多任务</span></span>
<span class="line"><span class="token class-name">CompletableFuture</span></span>
<span class="line">        <span class="token punctuation">.</span><span class="token function">supplyAsync</span><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token operator">-&gt;</span><span class="token number">1</span><span class="token operator">+</span><span class="token number">1</span><span class="token punctuation">)</span> <span class="token comment">//获取一个线程并执行</span></span>
<span class="line">        <span class="token punctuation">.</span><span class="token function">exceptionally</span><span class="token punctuation">(</span><span class="token punctuation">(</span>exception<span class="token punctuation">)</span><span class="token operator">-&gt;</span><span class="token punctuation">{</span> <span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span>exception<span class="token punctuation">.</span><span class="token function">getMessage</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token keyword">return</span> <span class="token number">0</span><span class="token punctuation">;</span><span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token comment">//若抛异常则这样处理</span></span>
<span class="line">        <span class="token punctuation">.</span><span class="token function">thenApply</span><span class="token punctuation">(</span><span class="token punctuation">(</span>result<span class="token punctuation">)</span><span class="token operator">-&gt;</span>x<span class="token operator">+</span><span class="token number">2</span><span class="token punctuation">)</span>  <span class="token comment">//使用上一步的线程，对上一步的结果进行处理</span></span>
<span class="line">        <span class="token punctuation">.</span><span class="token function">handle</span><span class="token punctuation">(</span><span class="token punctuation">(</span>result<span class="token punctuation">,</span>exception<span class="token punctuation">)</span><span class="token operator">-&gt;</span>x<span class="token operator">+</span><span class="token number">3</span><span class="token punctuation">)</span> <span class="token comment">//使用上一步的线程，对上一步的结果进行处理（若抛了异常也可处理）</span></span>
<span class="line">        <span class="token punctuation">.</span><span class="token function">whenComplete</span><span class="token punctuation">(</span><span class="token punctuation">(</span>result<span class="token punctuation">,</span>exception<span class="token punctuation">)</span><span class="token operator">-&gt;</span><span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span><span class="token string">&quot;x=&quot;</span><span class="token operator">+</span>x<span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">//最后一步处理</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">//多任务2</span></span>
<span class="line"><span class="token class-name">CompletableFuture</span></span>
<span class="line">        <span class="token punctuation">.</span><span class="token function">supplyAsync</span><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token operator">-&gt;</span><span class="token number">1</span><span class="token operator">+</span><span class="token number">1</span><span class="token punctuation">)</span> <span class="token comment">//获取一个线程并执行</span></span>
<span class="line">        <span class="token punctuation">.</span><span class="token function">thenApplyAsync</span><span class="token punctuation">(</span><span class="token punctuation">(</span>x<span class="token punctuation">)</span><span class="token operator">-&gt;</span>x<span class="token operator">+</span><span class="token number">2</span><span class="token punctuation">)</span><span class="token punctuation">;</span>  <span class="token comment">//获取一个新线程，处理上一步的结果</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">//生成UUID：谁先计算出结果，就用谁的</span></span>
<span class="line"><span class="token class-name">CompletableFuture</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">String</span><span class="token punctuation">&gt;</span></span> future1 <span class="token operator">=</span> <span class="token class-name">CompletableFuture</span></span>
<span class="line">        <span class="token punctuation">.</span><span class="token function">supplyAsync</span><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token operator">-&gt;</span><span class="token string">&quot;123456&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token class-name">CompletableFuture</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">String</span><span class="token punctuation">&gt;</span></span> future2 <span class="token operator">=</span> <span class="token class-name">CompletableFuture</span></span>
<span class="line">        <span class="token punctuation">.</span><span class="token function">supplyAsync</span><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token operator">-&gt;</span><span class="token string">&quot;567890&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token class-name">String</span> myuuid <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token class-name">String</span><span class="token punctuation">)</span><span class="token class-name">CompletableFuture</span><span class="token punctuation">.</span><span class="token function">anyOf</span><span class="token punctuation">(</span>future1<span class="token punctuation">,</span>future2<span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">get</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">//使用自定义线程池</span></span>
<span class="line"><span class="token class-name">ExecutorService</span> service <span class="token operator">=</span><span class="token keyword">new</span> <span class="token class-name">ThreadPoolExecutor</span><span class="token punctuation">(</span><span class="token number">0</span><span class="token punctuation">,</span> <span class="token class-name">Integer</span><span class="token punctuation">.</span><span class="token constant">MAX_VALUE</span><span class="token punctuation">,</span><span class="token number">60L</span><span class="token punctuation">,</span> <span class="token class-name">TimeUnit</span><span class="token punctuation">.</span><span class="token constant">SECONDS</span><span class="token punctuation">,</span></span>
<span class="line">        <span class="token keyword">new</span> <span class="token class-name">SynchronousQueue</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">Runnable</span><span class="token punctuation">&gt;</span></span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token class-name">CompletableFuture</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">Integer</span><span class="token punctuation">&gt;</span></span> future3 <span class="token operator">=</span> <span class="token class-name">CompletableFuture</span><span class="token punctuation">.</span><span class="token function">supplyAsync</span><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token operator">-&gt;</span><span class="token number">1</span><span class="token operator">+</span><span class="token number">1</span><span class="token punctuation">,</span>service<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token class-name">Integer</span> result3 <span class="token operator">=</span> future3<span class="token punctuation">.</span><span class="token function">get</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li></ul></li><li><p>关闭线程池</p></li></ol><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java"><pre><code class="language-java"><span class="line">service<span class="token punctuation">.</span><span class="token function">shutdown</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="任务队列满后的拒绝策略" tabindex="-1"><a class="header-anchor" href="#任务队列满后的拒绝策略"><span>任务队列满后的拒绝策略</span></a></h3><pre><code>* AbortPolicy（直接抛出异常，任务没有被执行。默认策略）
* DiscardOldestPolicy（放弃队列中最旧的任务，然后将新任务入队）
* DiscardPolicy（直接放弃任务，什么都不做）
* CallerRunsPolicy（会调用当前线程池的所在的线程去执行被拒绝的任务，缺点是会阻塞主线程）
</code></pre><h2 id="线程池创建工具-executors类-已不建议使用-建议直接new-threadpoolexecutor" tabindex="-1"><a class="header-anchor" href="#线程池创建工具-executors类-已不建议使用-建议直接new-threadpoolexecutor"><span>线程池创建工具：Executors类（已不建议使用，建议直接new ThreadPoolExecutor）</span></a></h2><table><thead><tr><th>线程池</th><th>corePoolSize</th><th>maxPoolSize</th><th>workQueue</th><th>workQueue初始化大小</th><th>拒绝策略</th><th>描述</th></tr></thead><tbody><tr><td>Executors.newFixedThreadPool()</td><td>new对象时传入</td><td>new对象时传入</td><td>LinkedBlockingQueue</td><td>Interger.MAX_VALUE</td><td>AbortPolicy</td><td>定长线程池。LinkedBlockingQueue默认size为Integer.MAX_VALUE，过多任务进队时会导致OOM</td></tr><tr><td>Executors.newCachedThreadPool()</td><td>0</td><td>Integer.MAX_VALUE</td><td>SynchronousQueue</td><td></td><td>AbortPolicy</td><td></td></tr><tr><td>Executors.newScheduledThreadPool()</td><td>new对象时传入</td><td>Integer.MAX_VALUE</td><td>DelayedWorkQueue</td><td>16</td><td>AbortPolicy</td><td>DelayedWorkQueue可变长，即队列是无界的，过多任务进队时会导致OOM</td></tr><tr><td>Executors.newSingleThreadExecutor()</td><td>1</td><td>1</td><td>LinkedBlockingQueue</td><td>Interger.MAX_VALUE</td><td>AbortPolicy</td><td>只有一个线程。LinkedBlockingQueue默认size为Integer.MAX_VALUE，过多任务进队时会导致OOM</td></tr></tbody></table><p>(1). 获取线程池</p><ul><li>可变长线程池</li></ul><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java"><pre><code class="language-java"><span class="line"><span class="token comment">//生成一个可变长线程池</span></span>
<span class="line"><span class="token class-name">ExecutorService</span> pool <span class="token operator">=</span> <span class="token class-name">Executors</span><span class="token punctuation">.</span><span class="token function">newCachedThreadPool</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>定长线程池</li></ul><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java"><pre><code class="language-java"><span class="line"><span class="token comment">//生成一个定长线程池</span></span>
<span class="line"><span class="token class-name">ExecutorService</span> pool <span class="token operator">=</span> <span class="token class-name">Executors</span><span class="token punctuation">.</span><span class="token function">newFixedThreadPool</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>轮询线程池</li></ul><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java"><pre><code class="language-java"><span class="line"><span class="token comment">//生成一个定长线程池（支持定时、周期性任务）</span></span>
<span class="line"><span class="token class-name">ExecutorService</span> pool <span class="token operator">=</span> <span class="token class-name">Executors</span><span class="token punctuation">.</span><span class="token function">newScheduledThreadPool</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>(2).获取线程执行任务</p><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java"><pre><code class="language-java"><span class="line"><span class="token comment">//</span></span>
<span class="line"><span class="token class-name">Future</span> future <span class="token operator">=</span> pool<span class="token punctuation">.</span><span class="token function">execute</span><span class="token punctuation">(</span><span class="token keyword">new</span> <span class="token class-name">Runnable</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="springboot的异步执行方法" tabindex="-1"><a class="header-anchor" href="#springboot的异步执行方法"><span>SpringBoot的异步执行方法</span></a></h2><p>通过@EnableAsync + @Async配置，即可使用SpringBoot维护的线程池</p><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java"><pre><code class="language-java"><span class="line"><span class="token comment">//在启动类增加@EnableAsync注解</span></span>
<span class="line"><span class="token annotation punctuation">@EnableAsync</span></span>
<span class="line"><span class="token annotation punctuation">@SpringBootApplication</span></span>
<span class="line"><span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">ManageApplication</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token comment">//...</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java"><pre><code class="language-java"><span class="line"><span class="token annotation punctuation">@Service</span></span>
<span class="line"><span class="token keyword">public</span> <span class="token class-name">MyService</span><span class="token punctuation">{</span></span>
<span class="line">    <span class="token comment">//定义一个异步执行的函数，被调用时使用默认的线程池执行</span></span>
<span class="line">    <span class="token annotation punctuation">@Async</span> </span>
<span class="line">    <span class="token keyword">public</span> <span class="token keyword">void</span> <span class="token function">test</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">{</span><span class="token comment">//...}</span></span>
<span class="line"></span>
<span class="line">    <span class="token comment">//使用名称为pool2的自定义线程池</span></span>
<span class="line">    <span class="token annotation punctuation">@Async</span><span class="token punctuation">(</span>value<span class="token operator">=</span><span class="token string">&quot;pool2&quot;</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token keyword">public</span> <span class="token keyword">void</span> <span class="token function">test2</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">{</span><span class="token comment">//...}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>默认的线程池配置：</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">#核心线程数</span>
<span class="line">spring.task.execution.pool.core-size=8</span>
<span class="line">#最大线程数</span>
<span class="line">spring.task.execution.pool.max-size=Integet.MAX_VALUE</span>
<span class="line">#空闲线程保留时间</span>
<span class="line">spring.task.execution.pool.keep-alive=60s</span>
<span class="line">#队列容量</span>
<span class="line">spring.task.execution.pool.queue-capacity=Integet.MAX_VALUE</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="volatile-integer-和atomicinteger的区别" tabindex="-1"><a class="header-anchor" href="#volatile-integer-和atomicinteger的区别"><span>volatile Integer 和AtomicInteger的区别？</span></a></h2><p>AtomicInteger： 本身即可满足线程安全的三个条件：原子性、可见性、有序性；</p><p>volatile Integer：只能满足可见性和有序性，所以遇到 i++这种操作，还是需要先加锁再操作。</p><h2 id="java里线程-thread-的生命周期" tabindex="-1"><a class="header-anchor" href="#java里线程-thread-的生命周期"><span>JAVA里线程（Thread）的生命周期？</span></a></h2><p>新建（new）<br> 就绪（runnable）<br> 运行 （running）<br> 阻塞（blocking）<br> 睡眠（time waiting，等待通知或等待一段时间）<br> 等待（waiting，等待通知）<br> 结束（dead）</p><h2 id="thread里的函数解析" tabindex="-1"><a class="header-anchor" href="#thread里的函数解析"><span>Thread里的函数解析</span></a></h2><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java"><pre><code class="language-java"><span class="line"><span class="token doc-comment comment">/**在调用interrupt时，若thread正被阻塞（等待IO、或在synchronized代码块前等待锁），则可让thread停止阻塞，抛出异常。</span>
<span class="line">若thread没有被阻塞，则不会抛出异常。</span>
<span class="line">若想在运行时也可以中断，可在thread的run()中加入isInterruped()的判断。</span>
<span class="line">**/</span></span>
<span class="line">thread<span class="token punctuation">.</span><span class="token function">interrupt</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token doc-comment comment">/**</span>
<span class="line">开始线程</span>
<span class="line">**/</span></span>
<span class="line">thread<span class="token punctuation">.</span><span class="token function">start</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token doc-comment comment">/**</span>
<span class="line">线程休眠（不会交出占用的锁）</span>
<span class="line">**/</span></span>
<span class="line">thread<span class="token punctuation">.</span><span class="token function">sleep</span><span class="token punctuation">(</span><span class="token keyword">long</span> millis<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token doc-comment comment">/**</span>
<span class="line">线程是否活跃</span>
<span class="line">**/</span></span>
<span class="line">thread<span class="token punctuation">.</span><span class="token function">isAlive</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token doc-comment comment">/**</span>
<span class="line">thread线程阻塞当前线程，当thread执行完后，当前线程才继续执行</span>
<span class="line">**/</span></span>
<span class="line">thread<span class="token punctuation">.</span><span class="token function">join</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="thread如何从一个生命周期进入另一个生命周期" tabindex="-1"><a class="header-anchor" href="#thread如何从一个生命周期进入另一个生命周期"><span>Thread如何从一个生命周期进入另一个生命周期？</span></a></h2><p>新建（new）</p><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java"><pre><code class="language-java"><span class="line"><span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token keyword">void</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token class-name">String</span><span class="token punctuation">[</span><span class="token punctuation">]</span> args<span class="token punctuation">)</span><span class="token punctuation">{</span></span>
<span class="line"><span class="token comment">//此时进入新建态</span></span>
<span class="line"><span class="token class-name">Thread</span> thread <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">MyThread</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>新建（new） --&gt; 就绪（runnable） 就绪（runnable） --&gt; 运行 （running）</p><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java"><pre><code class="language-java"><span class="line">thread<span class="token punctuation">.</span><span class="token function">start</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> </span>
<span class="line"><span class="token comment">//调用start()后获取到CPU时间片，start()再调用run()，此时才算正式进入运行态</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>运行 （running） --&gt; 阻塞（blocking）</p><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java"><pre><code class="language-java"><span class="line"><span class="token comment">//1.遇到同步代码块时，thread便会被阻塞</span></span>
<span class="line"><span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">MyThread</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">public</span> <span class="token keyword">void</span> <span class="token function">run</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">{</span></span>
<span class="line">        <span class="token function">synchronize</span><span class="token punctuation">(</span><span class="token keyword">this</span><span class="token punctuation">)</span><span class="token punctuation">{</span></span>
<span class="line">           <span class="token comment">// ...</span></span>
<span class="line">        <span class="token punctuation">}</span></span>
<span class="line">        </span>
<span class="line">    </span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>运行 （running） --&gt; 睡眠（time waiting） 运行 （running） --&gt; 等待（waiting）</p><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java"><pre><code class="language-java"><span class="line"><span class="token comment">//第一种：lock.wait()</span></span>
<span class="line"><span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">MyThread</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token class-name">Object</span> lock <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Object</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token keyword">public</span> <span class="token keyword">void</span> <span class="token function">run</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">{</span></span>
<span class="line">        <span class="token comment">//为什么wait()、notify()、notifyAll()需要在synchronized里执行？</span></span>
<span class="line">        <span class="token comment">//语法上：不写在synchronized内，运行时会抛出异常</span></span>
<span class="line">        <span class="token comment">//原理上：当前线程必须拥有对象的monitor（内置锁），调用对象的wait()、notify()、notifyAll()方法时才能有锁可以释放</span></span>
<span class="line">        <span class="token keyword">synchronized</span><span class="token punctuation">(</span> lock <span class="token punctuation">)</span><span class="token punctuation">{</span></span>
<span class="line">            <span class="token keyword">try</span> <span class="token punctuation">{</span></span>
<span class="line">                    <span class="token comment">// ...</span></span>
<span class="line">                    <span class="token comment">//释放lock对象，线程等待1s，1s后重新竞争lock对象，竞争到lock对象后继续往下走</span></span>
<span class="line">                    lock<span class="token punctuation">.</span><span class="token function">wait</span><span class="token punctuation">(</span><span class="token number">1000</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">                <span class="token punctuation">}</span> <span class="token keyword">catch</span> <span class="token punctuation">(</span><span class="token class-name">InterruptedException</span> e<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">                      e<span class="token punctuation">.</span><span class="token function">printStackTrace</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">                <span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line">        <span class="token punctuation">}</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java"><pre><code class="language-java"><span class="line"><span class="token comment">//第二种：thread.join() (实质是调用了thread.wait())</span></span>
<span class="line"><span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token keyword">void</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token class-name">String</span><span class="token punctuation">[</span><span class="token punctuation">]</span> args<span class="token punctuation">)</span><span class="token punctuation">{</span></span>
<span class="line"><span class="token comment">//此时进入新建态</span></span>
<span class="line"><span class="token class-name">Thread</span> thread <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">MyThread</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token comment">//等待thread执行完后，主线程再执行（等于异步变同步）</span></span>
<span class="line">thread<span class="token punctuation">.</span><span class="token function">join</span><span class="token punctuation">(</span><span class="token number">1000</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java"><pre><code class="language-java"><span class="line"><span class="token comment">//第三种：</span></span>
<span class="line"><span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">MyThread</span> <span class="token punctuation">{</span></span>
<span class="line"><span class="token keyword">public</span> <span class="token keyword">void</span> <span class="token function">run</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">{</span></span>
<span class="line">    <span class="token class-name">LockSupport</span><span class="token punctuation">.</span><span class="token function">pack</span><span class="token punctuation">(</span><span class="token keyword">this</span><span class="token punctuation">)</span><span class="token punctuation">;</span><span class="token comment">//当前线程等待，直至其他线程调用LockSupport.unpack(this)</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"><span class="token comment">//等待thread执行完后，主线程再执行（等于异步变同步）</span></span>
<span class="line">thread<span class="token punctuation">.</span><span class="token function">join</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>睡眠（time waiting） --&gt; 就绪（runnable）</p><div class="language-sql line-numbers-mode" data-highlighter="prismjs" data-ext="sql"><pre><code class="language-sql"><span class="line"><span class="token comment">/**</span>
<span class="line">1. lock.nofity() or lock.notifyAll() ; //对应第一种方式</span>
<span class="line">2. LockSupport.unpack(this) //对应第三种方式</span>
<span class="line">**/</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="有哪些常见的锁" tabindex="-1"><a class="header-anchor" href="#有哪些常见的锁"><span>有哪些常见的锁？</span></a></h2><table><thead><tr><th>类型</th><th>可重入</th><th>悲观锁</th><th>可中断锁</th><th>公平锁</th><th>互斥锁</th><th>独占锁</th></tr></thead><tbody><tr><td>synchronized</td><td>√</td><td>√</td><td>×</td><td>×</td><td>√</td><td>√</td></tr><tr><td>ReentrantLock</td><td>√</td><td>√</td><td>√</td><td>都可，默认非公平</td><td>√</td><td>√</td></tr><tr><td>ReentrantReadWriteLock</td><td>√</td><td>√</td><td>×</td><td>都可，默认非公平</td><td>×(读写锁)</td><td>读锁是共享锁，写锁是独占锁</td></tr><tr><td>Unsafe.compareAndSwap()</td><td>-</td><td>×</td><td>-</td><td>-</td><td>×(自旋锁)</td><td>-</td></tr><tr><td>Semaphore</td><td>-</td><td>√</td><td>-</td><td>都可，默认非公平</td><td>-</td><td>×</td></tr><tr><td>CountDownLatch</td><td>-</td><td>√</td><td>-</td><td>都可，默认非公平</td><td>-</td><td>×</td></tr></tbody></table><ul><li><p>可重入？ 当某个线程已调用该锁并持有，在被锁的代码段里面仍可以继续调用锁，则该锁是可重入锁； 换言之，当某线程调用锁，进入代码，然后再次调用锁，若此时不能继续进入该代码，则是不可重入锁。</p></li><li><p>悲观or乐观？ 当读、写都要调用锁，悲观锁； 读写都不锁，只有在写时检测是否有冲突，有冲突则返回错误给用户，乐观锁；</p></li><li><p>可中断？ 当线程A想要的锁一直被另一线程B占据，若线程A需要一直阻塞等待锁，即是不可中断锁； 反之，若线程A可等待一段时间后返回失败，则是可中断锁。</p></li><li><p>公平？ 若线程A最先请求锁，最终亦是线程A最先获得锁，那么该锁便是公平锁； 反之，若线程A不一定最先获得锁，便是不公平锁。</p></li><li><p>互斥or读写？ 当读、写都要调用锁，互斥锁； 当读时，大家可以共用该锁；写时，只有一人可以占用该锁，读写锁；</p></li><li><p>互斥or自旋？ 互斥锁(mutex)：竞争锁失败时，线程会挂起，进入阻塞态；等待解锁后，重新竞争CPU时间片 自旋锁(spin)：竞争锁失败时，线程不会挂起，而是一直轮询锁是否能用一段时间；一段时间内还获取不到，才挂起线程，进入阻塞态。</p></li><li><p>独占or共享？ 独占锁（写锁）：一个资源只能被线程上一次独占锁 共享锁（读锁）：一个资源能被多个线程上多次共享锁</p></li></ul><h2 id="乐观锁的优点" tabindex="-1"><a class="header-anchor" href="#乐观锁的优点"><span>乐观锁的优点</span></a></h2><h2 id="关于java乐观锁、自旋锁-unsafe类" tabindex="-1"><a class="header-anchor" href="#关于java乐观锁、自旋锁-unsafe类"><span>关于Java乐观锁、自旋锁：Unsafe类</span></a></h2><p>像原子类（AtomicInteger等类）、AbstractQueuedSynchronizer（AQS，ReentrantLock、CountDownLatch的底层实现），都是通过Unsafe类的CAS操作（乐观锁操作）实现。</p><blockquote><p>既然底层是通过乐观锁实现，那为什么说ReentrantLock是悲观锁？</p></blockquote><p>如何实例化Unsafe对象</p><blockquote><p>由Unsafe类的源码可知，只有JDK自带的类（即BootstrapClassLoader加载的类），才能使用getUnsafe()获取unsafe类 若开发者想自己获取unsafe类，只能通过反射方式获取（如下示例）：</p></blockquote><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java"><pre><code class="language-java"><span class="line">    <span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token keyword">void</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token class-name">String</span><span class="token punctuation">[</span><span class="token punctuation">]</span> args<span class="token punctuation">)</span></span>
<span class="line">        <span class="token keyword">throws</span> <span class="token class-name">NoSuchFieldException</span><span class="token punctuation">,</span> <span class="token class-name">IllegalAccessException</span> <span class="token punctuation">{</span></span>
<span class="line">        <span class="token class-name">Field</span> theUnsafe <span class="token operator">=</span> <span class="token class-name">Unsafe</span><span class="token punctuation">.</span><span class="token keyword">class</span><span class="token punctuation">.</span><span class="token function">getDeclaredField</span><span class="token punctuation">(</span><span class="token string">&quot;theUnsafe&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">        theUnsafe<span class="token punctuation">.</span><span class="token function">setAccessible</span><span class="token punctuation">(</span><span class="token boolean">true</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">        <span class="token class-name">Unsafe</span> unsafe <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token class-name">Unsafe</span><span class="token punctuation">)</span> theUnsafe<span class="token punctuation">.</span><span class="token function">get</span><span class="token punctuation">(</span><span class="token keyword">null</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">        <span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span>unsafe<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Unsafe类核心代码</p><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java"><pre><code class="language-java"><span class="line"><span class="token keyword">public</span> <span class="token keyword">final</span> <span class="token keyword">class</span> <span class="token class-name">Unsafe</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">private</span> <span class="token keyword">static</span> <span class="token keyword">final</span> <span class="token class-name">Unsafe</span> theUnsafe<span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">    <span class="token keyword">private</span> <span class="token class-name">Unsafe</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line">    <span class="token annotation punctuation">@CallerSensitive</span></span>
<span class="line">    <span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token class-name">Unsafe</span> <span class="token function">getUnsafe</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">        <span class="token class-name">Class</span> var0 <span class="token operator">=</span> <span class="token class-name">Reflection</span><span class="token punctuation">.</span><span class="token function">getCallerClass</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">        <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token operator">!</span><span class="token constant">VM</span><span class="token punctuation">.</span><span class="token function">isSystemDomainLoader</span><span class="token punctuation">(</span>var0<span class="token punctuation">.</span><span class="token function">getClassLoader</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">            <span class="token keyword">throw</span> <span class="token keyword">new</span> <span class="token class-name">SecurityException</span><span class="token punctuation">(</span><span class="token string">&quot;Unsafe&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">        <span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token punctuation">{</span></span>
<span class="line">            <span class="token keyword">return</span> theUnsafe<span class="token punctuation">;</span></span>
<span class="line">        <span class="token punctuation">}</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line">    <span class="token comment">//...</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line">    </span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="cas操作" tabindex="-1"><a class="header-anchor" href="#cas操作"><span>CAS操作</span></a></h2><p>Unsafe提供了3个CAS函数，来实现乐观锁。 所谓CAS函数，即compareAndSwapObject()、compareAndSwapInt()、compareAndSwapLong()。 它包含3个入参：要修改变量的内存位置、预期原值、要修改为的值 比如，有一个student对象，要使用自旋锁的方式，修改它的name属性。 CAS操作，若成功则返回true，失败则返回false</p><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java"><pre><code class="language-java"><span class="line"></span>
<span class="line">    <span class="token keyword">public</span> <span class="token keyword">void</span> <span class="token function">test</span><span class="token punctuation">(</span><span class="token class-name">Student</span> student<span class="token punctuation">,</span><span class="token class-name">String</span> newName<span class="token punctuation">)</span><span class="token punctuation">{</span></span>
<span class="line">        <span class="token comment">//1.获取unsafe，略</span></span>
<span class="line">        <span class="token keyword">try</span> <span class="token punctuation">{</span></span>
<span class="line">            <span class="token comment">//2.使用Unsafe类，实现上自旋锁修改name属性</span></span>
<span class="line">            <span class="token keyword">long</span> valueOffset <span class="token operator">=</span> unsafe<span class="token punctuation">.</span><span class="token function">objectFieldOffset</span><span class="token punctuation">(</span><span class="token class-name">Student</span><span class="token punctuation">.</span><span class="token keyword">class</span><span class="token punctuation">.</span><span class="token function">getDeclaredField</span><span class="token punctuation">(</span><span class="token string">&quot;name&quot;</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">            <span class="token class-name">String</span> oldName <span class="token operator">=</span> unsafe<span class="token punctuation">.</span><span class="token function">getAndSetObject</span><span class="token punctuation">(</span>student<span class="token punctuation">,</span> valueOffset<span class="token punctuation">,</span> newName<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">            <span class="token comment">//getAndSetObject()是自旋锁实现，实际也是调用compareAndSwapObject()方法</span></span>
<span class="line">        <span class="token punctuation">}</span> <span class="token keyword">catch</span> <span class="token punctuation">(</span><span class="token class-name">Exception</span> var1<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">            <span class="token keyword">throw</span> <span class="token keyword">new</span> <span class="token class-name">Error</span><span class="token punctuation">(</span>var1<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">        <span class="token punctuation">}</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="juc简介" tabindex="-1"><a class="header-anchor" href="#juc简介"><span>JUC简介</span></a></h2><h3 id="aqs" tabindex="-1"><a class="header-anchor" href="#aqs"><span>AQS</span></a></h3><ul><li>什么是AQS？</li></ul><p>抽象的队列式的同步器。</p><p>ReentrantLock/Semaphore/CountDownLatch的底层实现。</p><h2 id="lock接口" tabindex="-1"><a class="header-anchor" href="#lock接口"><span>Lock接口</span></a></h2><p>为什么有synchronized，还需要再提出Lock接口？</p><p>因为synchronized无法解决线程死锁的问题。 产生线程死锁需要满足以下条件：</p><ol><li>互斥条件（一段时间内某一资源仅为一线程所持有）</li><li>请求和保持条件（当线程请求资源而阻塞时，不会释放自己拥有的资源）</li><li>不可抢夺条件（线程为使用完的资源不能被剥夺，只能在使用完时释放）</li><li>环路等待条件（在发生死锁时，必然存在一个进程--资源的环形链，如下） 线程1占有锁1，等待锁2； 线程2占有锁2，等待锁3； ... 线程N占有锁N，等待锁1。</li></ol><p>解决线程死锁，一般方法是破坏条件3，即“不可抢夺条件”。</p><p>想破坏“不可抢夺条件”，有如下方法：</p><ol><li>线程能响应中断（对应lock.lockInterruptibly()）</li><li>线程可以非阻塞地获取锁（对应lock.tryLock()，获取不到立即返回false）</li><li>支持超时（对应lock.tryLock(long time)）</li></ol><p>从上面可看到，JDK1.5后发布的Lock接口有对应的API支持。</p><h3 id="reentrantlock" tabindex="-1"><a class="header-anchor" href="#reentrantlock"><span>ReentrantLock</span></a></h3><p>三个内部类：Sync、NonfairSync、FairSync。NonfairSync、FairSync集成Sync，而且都是AQS的实现类。</p><p>FairSync类：采用公平策略获取锁 NonfairSync：采用非公平策略获取锁（默认）</p><h2 id="juc-tools" tabindex="-1"><a class="header-anchor" href="#juc-tools"><span>JUC Tools</span></a></h2><h3 id="semaphore" tabindex="-1"><a class="header-anchor" href="#semaphore"><span>Semaphore</span></a></h3><p>Semaphore称为计数信号量，它允许n个任务同时访问某个资源，可以将信号量看做是在向外分发使用资源的许可证，只有成功获取许可证，才能使用资源。</p><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java"><pre><code class="language-java"><span class="line"><span class="token comment">//假设只能允许10个用户同时在线</span></span>
<span class="line"><span class="token class-name">Semaphore</span> semaphore<span class="token operator">=</span><span class="token keyword">new</span> <span class="token class-name">Semaphore</span><span class="token punctuation">(</span><span class="token number">10</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token comment">//用户登录，占用1个信号量</span></span>
<span class="line"><span class="token keyword">boolean</span> isLogin<span class="token operator">=</span> semaphore<span class="token punctuation">.</span><span class="token function">tryAcquire</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token comment">//查看剩余多少用户可以登录</span></span>
<span class="line"><span class="token keyword">int</span> restCount<span class="token operator">=</span>semaphore<span class="token punctuation">.</span><span class="token function">availablePermits</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="countdownlatch" tabindex="-1"><a class="header-anchor" href="#countdownlatch"><span>CountDownLatch</span></a></h3><p>CountDownLatch典型的用法是将一个程序分为n个互相独立的可解决任务，并创建值为n的CountDownLatch。当每一个任务完成时，都会在这个锁存器上调用countDown，等待问题被解决的任务调用这个锁存器的await，将他们自己拦住，直至锁存器计数结束。</p><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java"><pre><code class="language-java"><span class="line"><span class="token comment">//定义了一个计数器，当前计数为1</span></span>
<span class="line"><span class="token class-name">CountDownLatch</span> begin <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">CountDownLatch</span><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token comment">//阻塞当前线程，等待计数器到0</span></span>
<span class="line">begin<span class="token punctuation">.</span><span class="token function">await</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token comment">//（在另外的线程）任务完成，计数-1</span></span>
<span class="line">begin<span class="token punctuation">.</span><span class="token function">countDown</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="locksupport" tabindex="-1"><a class="header-anchor" href="#locksupport"><span>LockSupport</span></a></h3>`,203)]))}const i=s(t,[["render",l]]),u=JSON.parse('{"path":"/interview/JAVASE.html","title":"JAVA基础","lang":"en-US","frontmatter":{},"git":{"updatedTime":1774519764000,"contributors":[{"name":"dongyz8","username":"dongyz8","email":"dongyz8@gdii-yueyun.com","commits":1,"url":"https://github.com/dongyz8"}],"changelog":[{"hash":"cf707809cda8d06a8d3bbda287edbc5cfe5d46a1","time":1774519764000,"email":"dongyz8@gdii-yueyun.com","author":"dongyz8","message":"commit"}]},"filePathRelative":"interview/JAVASE.md"}');export{i as comp,u as data};
